const Require = require('../../../../../src/lib/annotations/resources/Require');
const { expect } = require('chai');

describe('@Require Annotation', () => {
  it('should have correct name and target', () => {
    expect(Require.name).to.equal('Require');
    expect(Require.target).to.equal('property');
  });

  it('should expect arguments', () => {
    expect(Require.args).to.be.true;
  });

  it('should have a description containing "Registers external modules"', () => {
    expect(Require.description).to.be.a('string');
    expect(Require.description).to.include('Registers external modules');
  });
});
